using HttpClient client = new HttpClient();
client.DefaultRequestHeaders.Add("Authorization", "Bearer YOUR_API_KEY");

// Get 13F data for a specific manager and quarter
var url = "https://api.sec-data.com/v1/form-13f?" +
    "cik=0001067983&" +
    "quarter_end=2024-12-31";

var response = await client.GetAsync(url);
var content = await response.Content.ReadAsStringAsync();

var options = new JsonSerializerOptions { PropertyNameCaseInsensitive = true };
var holdings = JsonSerializer.Deserialize<List<Holding>>(content, options);

var totalValue = holdings.Sum(h => h.ValueUsd);
var topPositions = holdings
    .OrderByDescending(h => h.ValueUsd)
    .Take(5)
    .ForEach(h => Console.WriteLine(
        $"{h.SecurityName}: {h.SharesHeld} shares, ${h.ValueUsd}K ({h.ValueUsd / (decimal)totalValue * 100:F2}%)"
    ));
